"use client";

// きっぷの払戻し・遅延証明書 — モバイル(375px)向けの旅客用画面。
// えきねっと / JR東日本 を想定。@gunjo/ui のコンポーネントで組む。
//   払戻し: 対象選択 → 理由 → 内容確認 → 受付完了 の4ステップ。
//   遅延証明書: TicketStub で QR つきの公式証明書を表示。
// ほぼ全パーツが @gunjo/ui 製。手組みは最終レポート参照。

import * as React from "react";
import {
  IconArrowRight,
  IconCircleCheck,
  IconCreditCard,
  IconBuildingStore,
  IconAlertTriangle,
  IconReceipt2,
  IconFileCertificate,
  IconTrain,
} from "@tabler/icons-react";
import {
  PageHeader,
  Card,
  CardHeader,
  CardTitle,
  CardContent,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  Stepper,
  Checkbox,
  RadioCardGroup,
  RadioCard,
  AmountBreakdown,
  MetadataList,
  Badge,
  Alert,
  AlertTitle,
  AlertDescription,
  Button,
  Separator,
  TicketStub,
  formatCurrency,
} from "@gunjo/ui";
import type { AmountLine, StepperStep, MetadataListItem } from "@gunjo/ui";

import {
  TICKETS,
  RESERVATION,
  REASON_INFO,
  REFUND_METHODS,
  DELAY_CERTIFICATE,
  computeRefund,
  makeReceiptNo,
  type RefundReason,
  type RefundMethod,
} from "./data";

type Step = "select" | "reason" | "confirm" | "done";

const STEP_ORDER: Step[] = ["select", "reason", "confirm", "done"];
const STEP_LABELS: Record<Step, string> = {
  select: "対象選択",
  reason: "理由・方法",
  confirm: "内容確認",
  done: "受付完了",
};

export default function TicketRefundPage() {
  return (
    <main className="mx-auto flex w-full max-w-md flex-1 flex-col bg-background">
      <Tabs defaultValue="refund" className="flex flex-1 flex-col">
        {/* PageHeader: onBack renders an accessible ≥44px back button itself.
            Do NOT also pass `leading` — the component treats them as mutually
            exclusive (leading shadows the back button), which would drop the
            click handler + aria-label. */}
        <PageHeader
          title="払戻し・遅延証明書"
          subtitle={RESERVATION.operator}
          backLabel="戻る"
          onBack={() => history.back()}
          sticky
          className="bg-card"
        />

        <div className="px-4 pt-3">
          <TabsList className="w-full">
            <TabsTrigger value="refund" className="flex-1">
              <IconReceipt2 className="mr-1.5 size-4" aria-hidden />
              払戻し
            </TabsTrigger>
            <TabsTrigger value="certificate" className="flex-1">
              <IconFileCertificate className="mr-1.5 size-4" aria-hidden />
              遅延証明書
            </TabsTrigger>
          </TabsList>
        </div>

        <TabsContent value="refund" className="flex-1 focus-visible:outline-none">
          <RefundFlow />
        </TabsContent>

        <TabsContent
          value="certificate"
          className="flex-1 focus-visible:outline-none"
        >
          <DelayCertificate />
        </TabsContent>
      </Tabs>
    </main>
  );
}

/* ───────────────────────── 払戻しフロー ───────────────────────── */

function RefundFlow() {
  const [step, setStep] = React.useState<Step>("select");
  const [selected, setSelected] = React.useState<string[]>(
    TICKETS.map((t) => t.id)
  );
  const [reason, setReason] = React.useState<RefundReason>("operator");
  const [method, setMethod] = React.useState<RefundMethod>("credit");
  const [receiptNo, setReceiptNo] = React.useState<string>("");

  const stepperSteps: StepperStep[] = STEP_ORDER.map((s) => ({
    label: STEP_LABELS[s],
    state:
      s === step
        ? "current"
        : STEP_ORDER.indexOf(s) < STEP_ORDER.indexOf(step)
          ? "completed"
          : "upcoming",
  }));

  const { fareTotal, feeTotal, refund } = computeRefund(selected, reason);
  const canProceedSelect = selected.length > 0;

  function toggle(id: string) {
    setSelected((prev) =>
      prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]
    );
  }

  function submit() {
    setReceiptNo(makeReceiptNo());
    setStep("done");
  }

  return (
    <div className="flex flex-col gap-4 px-4 pb-28 pt-2">
      <Stepper steps={stepperSteps} aria-label="払戻しの進行状況" className="px-0" />

      {step === "select" && (
        <SelectStep selected={selected} onToggle={toggle} />
      )}

      {step === "reason" && (
        <ReasonStep
          reason={reason}
          onReason={setReason}
          method={method}
          onMethod={setMethod}
          fareTotal={fareTotal}
          feeTotal={feeTotal}
          refund={refund}
        />
      )}

      {step === "confirm" && (
        <ConfirmStep
          selected={selected}
          reason={reason}
          method={method}
          fareTotal={fareTotal}
          feeTotal={feeTotal}
          refund={refund}
        />
      )}

      {step === "done" && (
        <DoneStep receiptNo={receiptNo} refund={refund} method={method} />
      )}

      {/* 固定フッターの操作ボタン */}
      {step !== "done" && (
        <div className="fixed inset-x-0 bottom-0 z-10 mx-auto max-w-md border-t border-border bg-card/95 px-4 py-3 backdrop-blur">
          <div className="mb-2 flex items-baseline justify-between">
            <span className="text-xs text-muted-foreground">払戻額</span>
            <span className="text-lg font-bold tabular-nums text-foreground">
              {formatCurrency(refund)}
            </span>
          </div>
          <div className="flex gap-2">
            {step !== "select" && (
              <Button
                variant="outline"
                size="lg"
                className="flex-1"
                onClick={() =>
                  setStep(STEP_ORDER[STEP_ORDER.indexOf(step) - 1])
                }
              >
                戻る
              </Button>
            )}
            {step === "select" && (
              <Button
                size="lg"
                variant="primary"
                className="flex-1"
                disabled={!canProceedSelect}
                onClick={() => setStep("reason")}
              >
                次へ（理由の選択）
                <IconArrowRight className="size-4" aria-hidden />
              </Button>
            )}
            {step === "reason" && (
              <Button
                size="lg"
                variant="primary"
                className="flex-1"
                onClick={() => setStep("confirm")}
              >
                内容を確認する
                <IconArrowRight className="size-4" aria-hidden />
              </Button>
            )}
            {step === "confirm" && (
              <Button
                size="lg"
                variant="primary"
                className="flex-1"
                onClick={submit}
              >
                この内容で払戻しを申込む
              </Button>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

/* ── ステップ1：払戻し対象の選択 ── */

function SelectStep({
  selected,
  onToggle,
}: {
  selected: string[];
  onToggle: (id: string) => void;
}) {
  const reservationMeta: MetadataListItem[] = [
    { label: "列車", value: RESERVATION.train },
    { label: "発車", value: RESERVATION.depart },
    { label: "到着", value: RESERVATION.arrive },
    { label: "座席", value: RESERVATION.seat },
    { label: "予約番号", value: RESERVATION.bookingNo },
  ];

  return (
    <section className="flex flex-col gap-4" aria-labelledby="select-heading">
      <Card>
        <CardHeader className="p-4 pb-0">
          <div className="flex items-center justify-between gap-2">
            <CardTitle as="h2" id="select-heading" className="text-base">
              ご予約内容
            </CardTitle>
            <Badge variant="warning" icon={<IconAlertTriangle className="size-3.5" />}>
              {RESERVATION.status}
            </Badge>
          </div>
        </CardHeader>
        <CardContent className="p-4 pt-3">
          <MetadataList items={reservationMeta} variant="compact" layout="horizontal" />
        </CardContent>
      </Card>

      <div>
        <h3 className="mb-1 px-1 text-sm font-semibold text-foreground">
          払戻すきっぷを選択
        </h3>
        <p className="mb-2 px-1 text-xs text-muted-foreground">
          乗車券・特急券は別々に払戻せます。
        </p>
        <ul className="flex flex-col gap-2">
          {TICKETS.map((t) => {
            const checked = selected.includes(t.id);
            return (
              <li key={t.id}>
                <label
                  className={`flex w-full cursor-pointer items-start gap-3 rounded-lg border bg-card p-4 transition-colors ${
                    checked ? "border-primary ring-1 ring-primary" : "border-border"
                  }`}
                >
                  <Checkbox
                    checked={checked}
                    onCheckedChange={() => onToggle(t.id)}
                    aria-label={`${t.kind} ${t.detail} を払戻し対象にする`}
                    className="mt-0.5"
                  />
                  <span className="min-w-0 flex-1">
                    <span className="flex items-center justify-between gap-2">
                      <span className="font-medium text-foreground">{t.kind}</span>
                      <span className="shrink-0 font-bold tabular-nums text-foreground">
                        {formatCurrency(t.amount)}
                      </span>
                    </span>
                    <span className="mt-0.5 block text-sm text-muted-foreground">
                      {t.detail}
                    </span>
                  </span>
                </label>
              </li>
            );
          })}
        </ul>
      </div>
    </section>
  );
}

/* ── ステップ2：理由・払戻方法 ── */

function ReasonStep({
  reason,
  onReason,
  method,
  onMethod,
  fareTotal,
  feeTotal,
  refund,
}: {
  reason: RefundReason;
  onReason: (r: RefundReason) => void;
  method: RefundMethod;
  onMethod: (m: RefundMethod) => void;
  fareTotal: number;
  feeTotal: number;
  refund: number;
}) {
  const info = REASON_INFO[reason];
  return (
    <section className="flex flex-col gap-5" aria-labelledby="reason-heading">
      <div>
        <h2 id="reason-heading" className="mb-2 px-1 text-sm font-semibold text-foreground">
          払戻し理由
        </h2>
        <RadioCardGroup
          value={reason}
          onValueChange={(v) => onReason(v as RefundReason)}
          aria-label="払戻し理由"
        >
          <RadioCard
            value="operator"
            title={REASON_INFO.operator.title}
            description={REASON_INFO.operator.note}
            highlight={REASON_INFO.operator.badge}
            leading={<IconTrain className="size-5 text-muted-foreground" />}
          />
          <RadioCard
            value="customer"
            title={REASON_INFO.customer.title}
            description={REASON_INFO.customer.note}
            highlight={REASON_INFO.customer.badge}
          />
        </RadioCardGroup>
        <Alert variant={reason === "operator" ? "success" : "info"} className="mt-2">
          <AlertTitle as="p">{info.badge}</AlertTitle>
          <AlertDescription>{info.note}</AlertDescription>
        </Alert>
      </div>

      <div>
        <h2 className="mb-2 px-1 text-sm font-semibold text-foreground">払戻方法</h2>
        <RadioCardGroup
          value={method}
          onValueChange={(v) => onMethod(v as RefundMethod)}
          aria-label="払戻方法"
        >
          {REFUND_METHODS.map((m) => (
            <RadioCard
              key={m.id}
              value={m.id}
              title={m.title}
              description={m.detail}
              highlight={`払戻しまで ${m.lead}`}
              leading={
                m.id === "credit" ? (
                  <IconCreditCard className="size-5 text-muted-foreground" />
                ) : (
                  <IconBuildingStore className="size-5 text-muted-foreground" />
                )
              }
            />
          ))}
        </RadioCardGroup>
      </div>

      <div>
        <h2 className="mb-2 px-1 text-sm font-semibold text-foreground">払戻金額（内訳）</h2>
        <Card>
          <CardContent className="p-4">
            <RefundBreakdown
              fareTotal={fareTotal}
              feeTotal={feeTotal}
              refund={refund}
            />
          </CardContent>
        </Card>
      </div>
    </section>
  );
}

/* ── 払戻金額の内訳（運賃合計 − 払戻手数料 = 払戻額） ── */

function RefundBreakdown({
  fareTotal,
  feeTotal,
  refund,
}: {
  fareTotal: number;
  feeTotal: number;
  refund: number;
}) {
  const lines: AmountLine[] = [
    { label: "運賃・料金合計", amount: fareTotal },
    {
      label: "払戻手数料",
      amount: feeTotal,
      kind: "subtract",
      note: feeTotal === 0 ? "運休・遅延のため手数料なし" : "きっぷ1枚ごとの所定額",
    },
  ];
  return (
    <AmountBreakdown
      lines={lines}
      total={{ label: "払戻額", amount: refund, tone: "positive" }}
      formula="払戻額 = 運賃・料金合計 − 払戻手数料"
    />
  );
}

/* ── ステップ3：内容確認 ── */

function ConfirmStep({
  selected,
  reason,
  method,
  fareTotal,
  feeTotal,
  refund,
}: {
  selected: string[];
  reason: RefundReason;
  method: RefundMethod;
  fareTotal: number;
  feeTotal: number;
  refund: number;
}) {
  const chosen = TICKETS.filter((t) => selected.includes(t.id));
  const methodInfo = REFUND_METHODS.find((m) => m.id === method)!;
  const confirmMeta: MetadataListItem[] = [
    {
      label: "払戻し対象",
      value: chosen.map((t) => t.kind).join("・"),
      description: RESERVATION.train,
    },
    { label: "払戻し理由", value: REASON_INFO[reason].title },
    {
      label: "払戻方法",
      value: methodInfo.title,
      description: `払戻しまで ${methodInfo.lead}`,
    },
  ];

  return (
    <section className="flex flex-col gap-4" aria-labelledby="confirm-heading">
      <h2 id="confirm-heading" className="px-1 text-sm font-semibold text-foreground">
        申込内容の確認
      </h2>

      <Card>
        <CardContent className="p-4">
          <MetadataList items={confirmMeta} />
        </CardContent>
      </Card>

      <Card>
        <CardContent className="p-4">
          <RefundBreakdown
            fareTotal={fareTotal}
            feeTotal={feeTotal}
            refund={refund}
          />
        </CardContent>
      </Card>

      <Alert variant="warning">
        <AlertTitle as="p">申込み後は取消できません</AlertTitle>
        <AlertDescription>
          払戻しを申込むと、対象のきっぷは無効になります。内容をご確認のうえお進みください。
        </AlertDescription>
      </Alert>
    </section>
  );
}

/* ── ステップ4：受付完了 ── */

function DoneStep({
  receiptNo,
  refund,
  method,
}: {
  receiptNo: string;
  refund: number;
  method: RefundMethod;
}) {
  const methodInfo = REFUND_METHODS.find((m) => m.id === method)!;
  const doneMeta: MetadataListItem[] = [
    { label: "受付番号", value: receiptNo },
    { label: "払戻額", value: formatCurrency(refund) },
    { label: "払戻方法", value: methodInfo.title },
    { label: "払戻しまでの目安", value: methodInfo.lead },
  ];
  return (
    <section
      className="flex flex-col items-center gap-4 pt-4 text-center"
      aria-labelledby="done-heading"
    >
      <div className="flex size-16 items-center justify-center rounded-full bg-success-subtle text-success-strong">
        <IconCircleCheck className="size-10" aria-hidden />
      </div>
      <div>
        <h2 id="done-heading" className="text-xl font-semibold text-foreground">
          払戻しを受付けました
        </h2>
        <p className="mt-1 text-sm text-muted-foreground">
          受付番号をお控えください。
        </p>
      </div>

      <Card className="w-full text-left">
        <CardContent className="p-4">
          <MetadataList items={doneMeta} />
        </CardContent>
      </Card>

      <Alert variant="info" className="w-full text-left">
        <AlertTitle as="p">払戻しの進捗はメールでお知らせします</AlertTitle>
        <AlertDescription>
          {method === "credit"
            ? "ご登録のクレジットカードへ、3〜5営業日で返金されます。"
            : "受付番号をみどりの窓口で提示してお受取りください。"}
        </AlertDescription>
      </Alert>

      <Button variant="outline" size="lg" className="w-full" onClick={() => history.back()}>
        予約一覧に戻る
      </Button>
    </section>
  );
}

/* ───────────────────────── 遅延証明書 ───────────────────────── */

function DelayCertificate() {
  const c = DELAY_CERTIFICATE;
  const certMeta: MetadataListItem[] = [
    { label: "対象日", value: c.date },
    { label: "路線", value: c.line },
    { label: "区間", value: c.section },
    { label: "遅延時分", value: `${c.delayMinutes}分` },
    { label: "理由", value: c.reason },
    { label: "発行番号", value: c.issueNo },
  ];

  return (
    <div className="flex flex-col gap-4 px-4 pb-10 pt-3">
      <Alert variant="info">
        <AlertTitle as="p">遅延証明書について</AlertTitle>
        <AlertDescription>
          勤務先などへの提出にご利用いただけます。QRコードで内容を照会できます。
        </AlertDescription>
      </Alert>

      <TicketStub
        format="qr"
        value={c.issueNo}
        codeLabel={c.issueNo}
        codeAlt={`遅延証明書 照会用QRコード ${c.issueNo}`}
      >
        <div className="flex flex-col gap-3">
          <div className="flex items-start justify-between gap-2">
            <div>
              <p className="text-xs font-medium uppercase tracking-wide text-muted-foreground">
                遅延証明書
              </p>
              <p className="mt-0.5 text-lg font-bold text-foreground">
                {c.delayMinutes}分の遅延
              </p>
            </div>
            <Badge variant="warning" icon={<IconAlertTriangle className="size-3.5" />}>
              遅延
            </Badge>
          </div>
          <Separator />
          <MetadataList items={certMeta} variant="compact" />
          <p className="text-xs text-muted-foreground">{c.issuedAt}・{RESERVATION.operator}</p>
        </div>
      </TicketStub>

      <div className="flex gap-2">
        <Button variant="outline" size="lg" className="flex-1">
          画像で保存
        </Button>
        <Button variant="primary" size="lg" className="flex-1">
          この証明書を提示
        </Button>
      </div>
    </div>
  );
}

// 払戻し対象データ — えきねっと / JR東日本 想定のリアルな値。
// 東京 → 新青森（東北新幹線 はやぶさ23号）の指定席を、運休 or お客様都合で払戻す前提。

export type RefundReason = "operator" | "customer";

export interface TicketComponent {
  /** 選択キー */
  id: string;
  /** 券種（乗車券 / 特急券 / 指定席）*/
  kind: string;
  /** 区間・列車などの説明 */
  detail: string;
  /** 額面（円）*/
  amount: number;
  /** お客様都合で払戻すときの手数料（円）。運休時は 0。 */
  customerFee: number;
}

export const TICKETS: TicketComponent[] = [
  {
    id: "ride",
    kind: "乗車券",
    detail: "東京 → 新青森（東北本線経由）",
    amount: 10010,
    customerFee: 220,
  },
  {
    id: "express",
    kind: "特急券・指定席",
    detail: "はやぶさ23号 7号車12番A席",
    amount: 7330,
    customerFee: 340,
  },
];

export const RESERVATION = {
  operator: "えきねっと（JR東日本）",
  bookingNo: "EK-20260628-4471",
  train: "東北新幹線 はやぶさ23号",
  depart: "2026年6月28日(日) 08:20 東京発",
  arrive: "11:23 新青森着",
  seat: "7号車 12番A席（普通車指定席・窓側）",
  status: "未使用（使用開始前）",
};

/** 払戻し理由ごとの規定文言。*/
export const REASON_INFO: Record<
  RefundReason,
  { title: string; badge: string; note: string }
> = {
  operator: {
    title: "運休・遅延（鉄道会社都合）",
    badge: "手数料なし・全額払戻",
    note: "運休、または2時間以上の遅延の場合は、払戻手数料なしで全額をお返しします。",
  },
  customer: {
    title: "お客様都合",
    badge: "払戻手数料あり",
    note: "ご都合による払戻しは、きっぷ1枚ごとに所定の払戻手数料がかかります（出発前まで）。",
  },
};

export type RefundMethod = "credit" | "counter";

export interface RefundMethodInfo {
  id: RefundMethod;
  title: string;
  detail: string;
  lead: string; // 払戻しまでの目安
}

export const REFUND_METHODS: RefundMethodInfo[] = [
  {
    id: "credit",
    title: "クレジットカードへ返金",
    detail: "ご購入カード（VISA ****4471）へ返金",
    lead: "3〜5営業日",
  },
  {
    id: "counter",
    title: "駅のみどりの窓口で受取",
    detail: "受付番号を提示して現金で受取",
    lead: "当日〜翌営業日",
  },
];

/** 遅延証明書データ。*/
export const DELAY_CERTIFICATE = {
  date: "2026年6月27日(土)",
  line: "JR東北本線（上り）",
  section: "盛岡 → 仙台",
  delayMinutes: 35,
  reason: "強風による徐行運転",
  issueNo: "DL-20260627-AO-00831",
  issuedAt: "2026年6月27日 19:42 発行",
};

/** 合計・手数料・払戻額を求める。*/
export function computeRefund(
  selectedIds: string[],
  reason: RefundReason
): { fareTotal: number; feeTotal: number; refund: number } {
  const chosen = TICKETS.filter((t) => selectedIds.includes(t.id));
  const fareTotal = chosen.reduce((s, t) => s + t.amount, 0);
  const feeTotal =
    reason === "operator"
      ? 0
      : chosen.reduce((s, t) => s + t.customerFee, 0);
  return { fareTotal, feeTotal, refund: fareTotal - feeTotal };
}

/** 受付番号を生成（本来はサーバ採番）。*/
export function makeReceiptNo(): string {
  return "RF-20260628-" + Math.floor(100000 + Math.random() * 899999);
}
